import pandas as pd
import matplotlib.pyplot as plt
import seaborn as sns

# 1. Read the data generated by your C++ engine
try:
    df = pd.read_csv('benchmark_results.csv')
except FileNotFoundError:
    print("Error: benchmark_results.csv not found. Run the C++ benchmarks first!")
    exit()

# 2. Setup the visual style (Dark Mode looks best for tech presentations)
plt.style.use('dark_background')
sns.set_theme(style="darkgrid", rc={"axes.facecolor": "#1e1e1e", "figure.facecolor":"#1e1e1e"})
plt.figure(figsize=(12, 7))

# 3. Plot your Engine's Data
plt.plot(df['Orders'], df['Avg_ns'], marker='o', linewidth=2, label='Your Engine - Average', color='#4C72B0')
plt.plot(df['Orders'], df['P50_ns'], marker='s', linestyle='--', label='Your Engine - P50 (Median)', color='#55A868')
plt.plot(df['Orders'], df['P99_ns'], marker='X', linewidth=2, label='Your Engine - P99 (Tail Latency)', color='#C44E52')

# 4. Overlay Industry Benchmarks (The "Professor Pitch")
plt.axhline(y=780, color='#E1C699', linestyle=':', linewidth=2, label='NanoARB (Rust HFT) - 780ns')
plt.axhline(y=1000, color='#8172B3', linestyle=':', linewidth=2, label='LMAX Disruptor - 1,000ns')
plt.axhline(y=5000, color='#CCB974', linestyle=':', linewidth=2, label='Standard Crypto Backend - 5,000ns+')

# 5. Formatting the Axes
plt.xscale('log') # Use Log scale for X because we go from 10k to 10M orders
plt.xlabel('Number of Orders Processed (Log Scale)', fontsize=12, color='white')
plt.ylabel('Latency per Order (Nanoseconds)', fontsize=12, color='white')
plt.title('O(1) Matching Engine Latency vs. Order Volume\n(Virtual Machine Hardware)', fontsize=16, fontweight='bold', color='white')

# Set Y-axis limit to focus on the sub-microsecond range
plt.ylim(0, max(df['P99_ns'].max() + 500, 1500)) 

plt.legend(loc='upper left', fontsize=10)
plt.tight_layout()

# 6. Save the image for your presentation
plt.savefig('latency_benchmark_graph.png', dpi=300, facecolor='#1e1e1e')
print("Success! Graph saved as 'latency_benchmark_graph.png'")
plt.show()